@app.route('/update_profile', methods=['PUT'])
@jwt_required()
def update_profile():
    current_user = get_jwt_identity()  # Assuming this gives us the user's ID or object
    data = request.get_json()

    # Define fields that can be updated
    updatable_fields = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']

    # Update only the fields present in the request and allowed
    for field in updatable_fields:
        if field in data:
            setattr(current_user, field, data[field])

    # Save changes to database (implementation depends on your ORM)
    # current_user.save()

    return jsonify({"message": "Profile updated successfully"}), 200

